import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.TWA1q3r6.js";const u=JSON.parse('{"title":"🤰 孕期准备","description":"","frontmatter":{"title":"🤰 孕期准备"},"headers":[],"relativePath":"stages/prenatal.md","filePath":"stages/prenatal.md"}'),n={name:"stages/prenatal.md"};function o(i,t,s,l,h,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="🤰-孕期准备" tabindex="-1">🤰 孕期准备 <a class="header-anchor" href="#🤰-孕期准备" aria-label="Permalink to &quot;🤰 孕期准备&quot;">​</a></h1><blockquote><p>从两条杠到产房的那些日子 —— 科学筹备，给自己一个安心的开始。</p></blockquote><hr><h2 id="🎯-这个阶段的关键任务" tabindex="-1">🎯 这个阶段的关键任务 <a class="header-anchor" href="#🎯-这个阶段的关键任务" aria-label="Permalink to &quot;🎯 这个阶段的关键任务&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优先级</th><th>任务</th><th>为什么重要</th><th>时间节点</th></tr></thead><tbody><tr><td>⭐⭐⭐</td><td>叶酸 400μg/日</td><td>降低神经管缺陷风险70%</td><td>孕前3月启动</td></tr><tr><td>⭐⭐⭐</td><td>规范产检</td><td>筛查妊娠糖尿病/子痫前期/胎儿异常</td><td>全孕期</td></tr><tr><td>⭐⭐</td><td>铁剂/复合维生素</td><td>贫血孕妇补铁降低早产率（按医嘱）</td><td>按需</td></tr><tr><td>⭐⭐</td><td>研究安全座椅+婴儿床</td><td>高单价品，锚定大促可省 ¥1,000+</td><td>距预产期6个月</td></tr></tbody></table><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><h3 id="安全必备" tabindex="-1">安全必备 <a class="header-anchor" href="#安全必备" aria-label="Permalink to &quot;安全必备&quot;">​</a></h3><h4 id="💊-叶酸-400μg-日-essential" tabindex="-1">💊 叶酸 400μg/日 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#💊-叶酸-400μg-日-essential" aria-label="Permalink to &quot;💊 叶酸 400μg/日 Essential&quot;">​</a></h4><p>降低神经管缺陷风险 <strong>70%</strong>，孕前3个月就应该开始补充。（CDC/WHO）</p><p><strong>选购</strong> 斯利安 / 爱乐维 / 汤臣倍健，药店OTC，约 ¥30-100/月</p><h4 id="🏥-规范产检-essential" tabindex="-1">🏥 规范产检 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🏥-规范产检-essential" aria-label="Permalink to &quot;🏥 规范产检 Essential&quot;">​</a></h4><p>筛查妊娠糖尿病、子痫前期、胎儿结构异常。产检不是走流程，是保护母婴安全的核心手段。（WHO/卫健委）</p><p><strong>选购</strong> 当地三甲医院产科建档，按卫健委产检时间表执行</p><h4 id="💊-铁剂-复合维生素-conditional" tabindex="-1">💊 铁剂/复合维生素 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#💊-铁剂-复合维生素-conditional" aria-label="Permalink to &quot;💊 铁剂/复合维生素 Conditional&quot;">​</a></h4><p>血检显示贫血时按医嘱补铁可降低早产率。没有贫血的话，均衡饮食即可。（WHO）</p><p><strong>选购</strong> 按医嘱处方，常见品牌右旋糖酐铁 / 多维元素片</p><h3 id="便利好物" tabindex="-1">便利好物 <a class="header-anchor" href="#便利好物" aria-label="Permalink to &quot;便利好物&quot;">​</a></h3><h4 id="🎒-待产包-标准化-essential" tabindex="-1">🎒 待产包（标准化） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🎒-待产包-标准化-essential" aria-label="Permalink to &quot;🎒 待产包（标准化） Essential&quot;">​</a></h4><p>产褥垫、一次性内裤、婴儿首套衣物 —— 入院刚需，提前准备心不慌。</p><p><strong>选购</strong> 十月结晶 / 子初 标准套装 ¥100-300，或按医院清单自行搭配</p><h4 id="🛋️-孕妇枕-conditional" tabindex="-1">🛋️ 孕妇枕 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🛋️-孕妇枕-conditional" aria-label="Permalink to &quot;🛋️ 孕妇枕 Conditional&quot;">​</a></h4><p>侧卧支撑缓解腰骶压力。不一定要专用款，家里普通枕头组合也能搞定。</p><p><strong>选购</strong> 佳韵宝 / Fossflakes ¥100-400，或用家里枕头替代</p><h3 id="情绪价值" tabindex="-1">情绪价值 <a class="header-anchor" href="#情绪价值" aria-label="Permalink to &quot;情绪价值&quot;">​</a></h3><h4 id="📷-孕妇摄影-conditional" tabindex="-1">📷 孕妇摄影 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#📷-孕妇摄影-conditional" aria-label="Permalink to &quot;📷 孕妇摄影 Conditional&quot;">​</a></h4><p>心理价值品类，不作科学评判。如果它能让你开心，就值得。</p><p><strong>选购</strong> 本地独立摄影师 ¥500-3,000，或和另一半自己拍</p><div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>防辐射孕妇服</strong> — 日常电磁辐射远低于致害阈值，无RCT支持，纯智商税</li><li><strong>家用胎心仪</strong> — NHS/RCOG明确反对：假阴性可能延误就医。替代：规范产检 + 数胎动</li><li><strong>胎教音箱/课程</strong> — 胎儿30周才发育听觉，你日常说话就是最好的&quot;胎教&quot;</li></ul></div><hr><h2 id="🌟-孕期多巴胺准备金" tabindex="-1">🌟 孕期多巴胺准备金 <a class="header-anchor" href="#🌟-孕期多巴胺准备金" aria-label="Permalink to &quot;🌟 孕期多巴胺准备金&quot;">​</a></h2><blockquote><p>给自己一些小确幸，让孕期多一点质感和愉悦。</p></blockquote><table tabindex="0"><thead><tr><th>物品</th><th>为什么值得</th><th>参考方向</th><th>预算</th></tr></thead><tbody><tr><td>☕ 一只好看的保温杯</td><td>日均喝水20+次，高频物品值得审美投资</td><td>Kinto / Snow Peak</td><td>¥200-350</td></tr><tr><td>🔊 白噪音音箱</td><td>孕晚期睡眠质量下降是生理事实</td><td>Muji壁挂 / Marshall</td><td>¥300-1,200</td></tr><tr><td>🧣 高支数纱布盖毯</td><td>孕期体温偏高，沙发午休神器</td><td>fog linen work / 良良竹纤维</td><td>¥150-500</td></tr><tr><td>👖 孕期运动裤</td><td>舒适+外出不尴尬，一条就够</td><td>lululemon Align / Maia Active</td><td>¥300-750</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">⏰ 采购小贴士</p><p>这个阶段的重点不是买买买，而是<strong>研究</strong>。花时间了解安全座椅和婴儿床，等最近的618或双11再下手，高单价品可以省 ¥1,000-2,000。详见 <a href="/linyuhan-baby-guide/pricing.html">价格择时</a>。</p></div>',35)])])}const b=a(n,[["render",o]]);export{u as __pageData,b as default};
